205		// get the resolved OS accent color from the device cache first, regardless
206		// of whether a default was configured, so we never repeat the underlying
207		// OS query (e.g. a DWM registry read) once we know the answer.
208		accent, OK := cache.Get[*Set](cache.Device, accentColor)
209		if !OK {
