270	func (d *Defaults) ToAnsi(ansiColor Ansi, isBackground bool) Ansi {
271		if ansiColor == "" {
272			return emptyColor
273		}
274	
275		if ansiColor.IsTransparent() {
276			return ansiColor
277		}
278	
279		// a gradient rides the ANSI plumbing as a plain string; the terminal writer detects
280		// and renders it per cell, so it must never be mangled into hex/256 parsing here.
281		if ansiColor.IsGradient() {
282			return ansiColor
283		}
284	
285		if ansiColor == Accent {
286			if d.accent == nil {
287				return emptyColor
288			}
289	
290			if isBackground {
291				return d.accent.Background
292			}
293	
294			return d.accent.Foreground
295		}
296	
297		colorFromName, err := getAnsiColorFromName(ansiColor, isBackground)
298		if err == nil {
299			return colorFromName
300		}
301	
302		colorString := ansiColor.String()
303	
304		if !strings.HasPrefix(colorString, "#") {
305			val, err := strconv.ParseUint(colorString, 10, 64)
306			if err != nil || val > 255 {
307				return emptyColor
308			}
309	
310			c256 := color.C256(uint8(val), isBackground)
311			return Ansi(c256.String())
312		}
313	
314		style := color.HEX(colorString, isBackground)
315		if !style.IsEmpty() {
