358	func (p *PaletteColors) ToAnsi(colorString Ansi, isBackground bool) Ansi {
359		// a gradient string is not a palette key; guard it explicitly so it never round-trips
360		// through palette resolution and reaches the next decorator untouched.
361		if colorString.IsGradient() {
362			return colorString
363		}
364	
365		paletteColor, err := p.palette.ResolveColor(colorString)
366		if err != nil {
367			return emptyColor
368		}
369	
370		ansiColor := p.ansiColors.ToAnsi(paletteColor, isBackground)
371	
372		return ansiColor
373	}
