379	// Cached is the AnsiColors Decorator that does simple color lookup caching.
380	// ToColor calls are cheap, but not free, and having a simple cache in
381	// has measurable positive effect on performance.
382	type Cached struct {
383		ansiColors String
384		colorCache map[cachedColorKey]Ansi
385	}
