387	type cachedColorKey struct {
388		colorString  Ansi
389		isBackground bool
390	}
391	
392	func (c *Cached) ToAnsi(colorString Ansi, isBackground bool) Ansi {
393		if c.colorCache == nil {
394			c.colorCache = make(map[cachedColorKey]Ansi)
395		}
396	
397		key := cachedColorKey{colorString, isBackground}
398		if ansiColor, hit := c.colorCache[key]; hit {
399			return ansiColor
400		}
401	
402		ansiColor := c.ansiColors.ToAnsi(colorString, isBackground)
403		c.colorCache[key] = ansiColor
404		return ansiColor
405	}
406	
407	func (c *Cached) Resolve(colorString Ansi) (Ansi, error) {
408		return c.ansiColors.Resolve(colorString)
