59	func asPaletteKey(colorName Ansi) (Ansi, bool) {
60		prefix, isKey := isPaletteKey(colorName)
61		if !isKey {
62			return "", false
63		}
64	
65		key := strings.TrimPrefix(colorName.String(), prefix.String())
66	
67		return Ansi(key), true
68	}
