81		keys := make([]string, 0, len(p.palette))
82		for key := range p.palette {
83			keys = append(keys, key.String())
84		}
85		sort.Strings(keys)
86		allColors := strings.Join(keys, ",")
87		errorStr := fmt.Sprintf(paletteKeyError, p.Key, allColors)
